const query = $fromAI('input', 'Producto o consulta', 'string').toLowerCase().trim();
let productos = [];

try {
  productos = $('Consultar Catálogo Productos').all();
} catch (e) {
  return "ERROR_BD: " + e.message;
}

if (!productos || productos.length === 0) {
  return "La base de datos de productos esta vacia o inaccesible.";
}

const disponibles = productos.filter(p => p.json.is_available !== false && p.json.deleted_at === null);

const keywordsMenu = ['menu','carta','todo','ver','mostrar','comer','tienen','opciones','disponible','hamburguesas','burguer','picoteo','entrante','patata','sandwiches'];

if (keywordsMenu.some(kw => query.includes(kw)) || query.length < 4) {
  const grouped = {};
  disponibles.forEach(p => {
    const item = p.json;
    let cat = 'OTROS';
    if (item.category_id === '0bc02f87-623d-4b2a-9ee2-1f7a6e5fde1e') cat = 'HAMBURGUESAS';
    else if (item.category_id === '433580a0-f34c-4e36-975c-a2b9f1bbb6b2') cat = 'ENTRANTES Y PICOTEO';
    else if (item.category_id === 'bae3f11e-df43-44b7-82ed-7c2a77098c82') cat = 'PATATAS';
    else if (item.category_id === '9dac7b28-9e2c-428c-b7c5-6559485fc644') cat = 'SANDWICHES';
    if (!grouped[cat]) grouped[cat] = [];
    grouped[cat].push(item);
  });

  const orden = ['HAMBURGUESAS', 'ENTRANTES Y PICOTEO', 'PATATAS', 'SANDWICHES', 'OTROS'];
  let res = "=== CARTA POZU 2.0 ===\n\n";
  orden.forEach(cat => {
    if (grouped[cat] && grouped[cat].length > 0) {
      res += `[${cat}]\n`;
      grouped[cat].forEach(i => res += `- ${i.name}: ${i.price}EUR\n`);
      res += "\n";
    }
  });
  return res + "Que te apetece pedir?";
}

const queryWords = query.split(/\s+/).filter(w => w.length > 2);
const matches = disponibles.filter(p => {
  const nombre = (p.json.name || '').toLowerCase();
  const desc = (p.json.description || '').toLowerCase();
  if (nombre.includes(query)) return true;
  if (desc.includes(query)) return true;
  return queryWords.some(word => nombre.includes(word));
});

if (matches.length === 1) {
  const m = matches[0].json;
  const ing = Array.isArray(m.ingredients) ? m.ingredients.join(', ') : 'Ver descripcion';
  return `PRODUCTO: ${m.name} | PRECIO: ${m.price}EUR | INFO: ${m.description} | INGREDIENTES: ${ing} | ALERGENOS: ${m.allergens || 'Sin especificar'}`;
}

if (matches.length > 1) {
  return `Encontre varios productos:\n${matches.map(m => `- ${m.json.name} (${m.json.price}EUR)`).join('\n')}\nA cual te refieres?`;
}

return `No encuentro "${query}" en la carta. Productos disponibles:\n${disponibles.map(p => `- ${p.json.name}`).join('\n')}`;

