const fecha = $fromAI('fecha', 'Fecha de la reserva (YYYY-MM-DD)', 'string');
const hora = $fromAI('hora', 'Hora deseada (HH:MM)', 'string');
const personas = $fromAI('personas', 'Número de personas', 'number');

let horarios = [];
let mesas = [];
let reservas = [];

try {
  horarios = $('Consultar Horarios').all();
  mesas = $('Consultar Mesas').all();
  reservas = $('Consultar Reservas Fecha').all();
} catch (e) {
  return "ERROR_BD: " + e.message;
}

if (!horarios || horarios.length === 0) {
  return "No hay horarios configurados en el sistema.";
}

if (!mesas || mesas.length === 0) {
  return "No hay mesas configuradas en el sistema.";
}

const mesasDisponibles = mesas.filter(m => m.json.is_available && m.json.capacity >= personas);

if (mesasDisponibles.length === 0) {
  return `No tenemos mesas disponibles para ${personas} personas. Capacidad máxima por mesa: ${Math.max(...mesas.map(m => m.json.capacity))}.`;
}

const reservasFecha = reservas.filter(r => r.json.reservation_date === fecha && r.json.status !== 'cancelled');

const horariosDisponibles = horarios.filter(h => h.json.is_available);

const horaDeseada = horariosDisponibles.find(h => h.json.open_time === hora);

if (!horaDeseada) {
  const alternativas = horariosDisponibles.map(h => h.json.open_time).join(', ');
  return `La hora ${hora} no está disponible. Horarios disponibles: ${alternativas}.`;
}

const mesasOcupadas = reservasFecha
  .filter(r => r.json.time_slot_id === horaDeseada.json.id)
  .map(r => r.json.table_id);

const mesasLibres = mesasDisponibles.filter(m => !mesasOcupadas.includes(m.json.id));

if (mesasLibres.length > 0) {
  return `✅ HAY DISPONIBILIDAD para ${personas} personas el ${fecha} a las ${hora}. Mesas disponibles: ${mesasLibres.length}.`;
} else {
  const otrasHoras = horariosDisponibles
    .filter(h => h.json.id !== horaDeseada.json.id)
    .map(h => h.json.open_time)
    .join(', ');
  return `❌ NO HAY MESAS LIBRES a las ${hora}. Horas alternativas: ${otrasHoras}.`;
}

const fecha = $fromAI('fecha', 'Fecha de la reserva (YYYY-MM-DD)', 'string');
const hora = $fromAI('hora', 'Hora de la reserva (HH:MM)', 'string');
