// Parse the detalle string into individual order items
// Expected format: "1 Cielito Lindo (12€)" or "2 Nachos (9.5€), 1 Pozu (12€)"
const orderId = $input.first().json.id;
const detalle = $input.first().json.items?.detalle || '';

// Split by comma or newline
const lines = detalle.split(/[,\n]/).map(l => l.trim()).filter(Boolean);

const items = [];
for (const line of lines) {
  // Match: "2 Nombre del producto (12€)" or "1 Nombre (12.5€)"
  const match = line.match(/^(\d+)\s+(.+?)(?:\s*\(([\d.]+)€?\))?\s*$/);
  if (match) {
    items.push({
      order_id: orderId,
      quantity: parseInt(match[1]) || 1,
      product_name: match[2].trim(),
      unit_price: parseFloat(match[3]) || 0,
      customizations: null
    });
  } else if (line.trim()) {
    // Fallback: treat whole line as 1 unit
    items.push({
      order_id: orderId,
      quantity: 1,
      product_name: line.replace(/\(.*?\)/g, '').trim(),
      unit_price: 0,
      customizations: null
    });
  }
}

// If nothing parsed, create a fallback item
if (items.length === 0) {
  items.push({
    order_id: orderId,
    quantity: 1,
    product_name: detalle || 'Pedido',
    unit_price: parseFloat($input.first().json.total) || 0,
    customizations: null
  });
}

return items;

