if (negocio.some(c => accion === c))   categoria = 'negocio';
else if (pagos.some(c => accion === c))     categoria = 'pagos';
else if (productos.some(c => accion === c)) categoria = 'productos';
else if (pedidos.some(c => accion === c))   categoria = 'pedidos';
